<a href="/portal/inspection-templates" class="small text-decoration-none">&larr; Inspection Templates</a><div class="d-flex justify-content-between align-items-start mt-2 mb-4"><div><h1 class="h3 mb-1"><?=e($template['name'])?></h1><p class="text-muted"><?=e($template['entity_type'])?> inspection · <?=e($template['description']??'')?></p></div></div>
<div class="row g-4"><div class="col-lg-4"><div class="card shadow-sm"><div class="card-body"><h2 class="h5">Add Item</h2><form method="post" action="/portal/inspection-templates/<?=$template['id']?>/items" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Section</label><input name="section_name" class="form-control"></div><div class="col-12"><label class="form-label">Label</label><input name="label" class="form-control" required></div><div class="col-12"><label class="form-label">Field Type</label><select name="field_type" class="form-select"><option>checkbox</option><option>text</option><option>textarea</option><option>number</option><option>select</option><option>photo</option><option>signature</option></select></div><div class="col-12"><label class="form-label">Select options</label><input name="options" class="form-control" placeholder="Pass, Fail, N/A"></div><div class="col-6"><label class="form-label">Sort</label><input type="number" name="sort_order" value="100" class="form-control"></div><div class="col-6 form-check mt-5"><input type="checkbox" name="required" class="form-check-input" id="req"><label for="req" class="form-check-label">Required</label></div><div class="col-12"><button class="btn btn-primary w-100">Add Item</button></div></form></div></div></div><div class="col-lg-8"><div class="card shadow-sm"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Section</th><th>Item</th><th>Type</th><th>Required</th><th></th></tr></thead><tbody><?php foreach($items as $i):?><tr><td><?=e($i['section_name'])?></td><td><?=e($i['label'])?></td><td><?=e($i['field_type'])?></td><td><?=$i['required']?'Yes':'No'?></td><td><form method="post" action="/portal/inspection-items/<?=$i['id']?>/delete"><?=csrf_field()?><button class="btn btn-sm btn-outline-danger">Delete</button></form></td></tr><?php endforeach?><?php if(!$items):?><tr><td colspan="5" class="text-center text-muted py-5">No items configured.</td></tr><?php en